package com.bookmyticket.service;
import com.bookmyticket.entity.*; import com.bookmyticket.repository.*; import jakarta.transaction.Transactional; import lombok.RequiredArgsConstructor; import org.springframework.stereotype.Service; import java.math.BigDecimal; import java.time.LocalDateTime; import java.util.*;
@Service @RequiredArgsConstructor
public class BookingService { private final BookingRepository bookingRepository; private final BookingSeatRepository bookingSeatRepository; private final ShowRepository showRepository; private final UserRepository userRepository;
 public Set<String> bookedSeats(Long showId){ Set<String> s=new HashSet<>(); bookingSeatRepository.findByShowId(showId).forEach(b->s.add(b.getSeatNumber())); return s; }
 @Transactional public synchronized Booking book(Long userId, Long showId, List<String> seats){ if(seats==null||seats.isEmpty()) throw new IllegalArgumentException("Please select at least one seat"); Show show=showRepository.findById(showId).orElseThrow(); User user=userRepository.findById(userId).orElseThrow(); for(String seat:seats){ if(bookingSeatRepository.existsByShowIdAndSeatNumber(showId,seat)) throw new IllegalArgumentException("Seat already booked: "+seat); } Booking booking=Booking.builder().user(user).show(show).status(BookingStatus.CONFIRMED).bookingDateTime(LocalDateTime.now()).totalPrice(show.getPrice().multiply(BigDecimal.valueOf(seats.size()))).bookingSeats(new ArrayList<>()).build(); for(String seat:seats){ booking.getBookingSeats().add(BookingSeat.builder().booking(booking).show(show).seatNumber(seat).build()); } return bookingRepository.save(booking); }
}
